public struct FfiConverterTypeFfiServerApiClient: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = FfiServerApiClient

    public static func lift(_ handle: UInt64) throws -> FfiServerApiClient {
        return FfiServerApiClient(unsafeFromHandle: handle)
    }

    public static func lower(_ value: FfiServerApiClient) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiServerApiClient {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: FfiServerApiClient, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


